WHERE {
  ?uri wdt:P451 wd:Q4205826 .
  ?uri wdt:P451 wd:Q4463198 .
  ?uri wdt:P31 wd:Q5 .
  FILTER NOT EXISTS { ?uri wdt:P26 wd:Q4205826 }
  FILTER NOT EXISTS { ?uri wdt:P26 wd:Q4463198 }
}

