SELECT ?uri WHERE {
  ?uri wdt:P31 wd:Q5 ;
        wdt:P1411 wd:Q181278 .
  FILTER EXISTS {
    ?uri wdt:P2522 ?medal .
    FILTER (?medal = wd:Q114721 = wd:Q688227  || ?medal = wd:Q875379 || ?medal = wd:Q875383)
  }
  FILTER EXISTS {
    ?uri wdt:P2416 ?discipline .
    ?discipline wdt:P31 wd:Q1506948
  }
}

SELECT ?uri (COUNT(?season) AS ?count) WHERE {
  ?uri wdt:P31 wd:Q13406458 ;
        wdt:P118 wd:Q128109 ;
        wdt:P2522 wd:Q18156668 .
  ?uri wdt:P5138 ?season .
} GROUP BY ?uri HAVING (?count > 1)

SELECT ?start ?end WHERE {
  wd:Q25369 wdt:P54 wd:Q121783;
                wdt:P551 ?start.
  wd:Q36159 wdt:P54 wd:Q121783;
                wdt:P551 ?end.
  FILTER (?start < ?end)
}

