SELECT ?university (COUNT(DISTINCT ?founder) AS ?count) WHERE {
  ?founder wdt:P112 wd:Q860580 .
  ?founder wdt:P69 ?university .
}
GROUP BY ?university
HAVING (COUNT(DISTINCT ?founder) > 1)

